def evaluate_4_12(student_func):
    def evaluator(text):
        length = len(text)
        if length < 20:
            return (0.3, "太短")
        elif length < 40:
            return (0.6, "还不够详细")
        return (0.9, "OK")
    def improver(text, issues):
        return text + " " + "补充更多细节以解决: " + issues
    r = student_func("短", evaluator, improver, max_iter=3)
    assert r["iterations"] <= 3
    assert r["final_score"] >= 0.8, f"最终分数应≥0.8, 得到{r['final_score']}"
    assert len(r["final"]) > 10
    return True, "关卡通过：正确实现Reflection模式"

